/*
 * Minimal HTMX-compatible shim — supports a focused subset of htmx.org
 * features used by the app. NOT a drop-in for htmx; replace with the
 * official build when we need the full feature surface. What works:
 *
 *   hx-post, hx-get                    on forms or arbitrary elements
 *   hx-target                          css selector, "this", or "find <sel>"
 *   hx-swap                            "innerHTML" (default), "outerHTML",
 *                                      "beforeend", "afterbegin",
 *                                      "beforebegin", "afterend", "none"
 *                                      ("none" suppresses the swap so a
 *                                      caller can do its own DOM work via
 *                                      hx-on::after-request).
 *                                      Trailing modifier tokens (e.g.
 *                                      "outerHTML show:window:top") are
 *                                      tolerated — only the first token
 *                                      is honored, the rest are ignored.
 *   hx-on::after-request               inline JS body that runs after
 *                                      every request (success or fail)
 *                                      with `event.detail.successful`
 *                                      set per the response status. The
 *                                      colon-prefix form `hx-on:htmx:
 *                                      after-request` is also accepted.
 *                                      Use this for popover auto-close,
 *                                      page reload, or any post-request
 *                                      side effect that doesn't fit a
 *                                      server-driven HX-Refresh /
 *                                      HX-Redirect.
 *   hx-select                          css selector applied to the
 *                                      response body before swap; lets
 *                                      a route serving a full page be
 *                                      sliced down to one element. Prefer
 *                                      returning a partial server-side;
 *                                      this is the back-compat hatch.
 *   hx-trigger                         "load", "toggle once" (on <details>),
 *                                      "change", "input changed delay:Nms",
 *                                      "every Ns" / "every Nms" (polling),
 *                                      omitted → submit (forms) / click (other)
 *   hx-indicator                       css selector; element gets .htmx-request
 *                                      added while the fetch is in flight
 *   hx-confirm                         window.confirm() before firing
 *   hx-vals                            JSON object of extra form fields
 *   hx-include                         css selector; "closest <sel>" or plain
 *                                      selector — merges those elements' form
 *                                      controls into the request body
 *   hx-swap-oob                        out-of-band swap on response elements;
 *                                      "true" = replace outerHTML of element
 *                                      with matching id; "innerHTML" / any
 *                                      other swap mode also supported
 *   HX-Request request header.
 *   HX-Trigger / HX-Redirect / HX-Refresh / HX-Location response headers
 *   are honored.
 *
 * Events dispatched (bubbling CustomEvents on the swap target):
 *   htmx:afterSwap                    fired after every successful swap
 *                                     so listeners can re-scan the DOM,
 *                                     stop polling, etc.
 *
 * Polling-stop hatch: a `hx-trigger="every Ns"` polling loop on an
 * element will halt automatically when that attribute is removed at
 * runtime (`el.removeAttribute("hx-trigger")`). Used by the job-modal
 * partial to stop polling once a job goes terminal.
 */
(function () {
  var IN_FLIGHT_CLASS = "htmx-request";

  function qs(root, sel) {
    try { return root.querySelector(sel); } catch (e) { return null; }
  }

  function findTarget(el) {
    var sel = el.getAttribute("hx-target");
    if (!sel || sel === "this") return el;
    if (sel === "closest form") {
      var f = el.closest("form");
      return f || el;
    }
    if (sel.indexOf("closest ") === 0) {
      var c = el.closest(sel.slice(8).trim());
      return c || el;
    }
    if (sel.indexOf("find ") === 0) {
      var f2 = qs(el, sel.slice(5).trim());
      return f2 || el;
    }
    return qs(document, sel) || el;
  }

  function indicatorEls(el) {
    var sel = el.getAttribute("hx-indicator");
    if (!sel) return [];
    var out = [];
    // Support "closest ..." / "find ..." on hx-indicator too.
    if (sel.indexOf("closest ") === 0) {
      var c = el.closest(sel.slice(8).trim());
      if (c) out.push(c);
    } else if (sel.indexOf("find ") === 0) {
      var f = qs(el, sel.slice(5).trim());
      if (f) out.push(f);
    } else {
      var list = document.querySelectorAll(sel);
      for (var i = 0; i < list.length; i++) out.push(list[i]);
    }
    return out;
  }

  function setBusy(el, busy) {
    var inds = indicatorEls(el);
    for (var i = 0; i < inds.length; i++) {
      if (busy) inds[i].classList.add(IN_FLIGHT_CLASS);
      else inds[i].classList.remove(IN_FLIGHT_CLASS);
    }
    if (busy) el.classList.add(IN_FLIGHT_CLASS);
    else el.classList.remove(IN_FLIGHT_CLASS);
  }

  // Fire an htmx:* event on the given element, bubbling so any
  // ancestor with addEventListener("htmx:foo", …) catches it. Mirrors
  // the subset of real-htmx events callers in this codebase listen
  // for (afterSwap is the load-bearing one — _job_modal.html uses it
  // to stop polling once the embedded job partial flips terminal).
  function fireHxEvent(target, name, detail) {
    if (!target || !target.dispatchEvent) return;
    try {
      target.dispatchEvent(new CustomEvent("htmx:" + name, {
        bubbles: true, cancelable: false, detail: detail || {},
      }));
    } catch (e) { /* dispatchEvent rarely throws but stay defensive */ }
  }

  function swap(target, html, mode) {
    // Tolerate htmx.org-style swap modifiers ("outerHTML show:window:top",
    // "innerHTML scroll:bottom", etc.) by taking only the leading mode
    // token. Without this, exact-string mode === "outerHTML" misses on
    // any modifier-bearing value and falls through to innerHTML — which
    // is the bug class that lets a full-page response (sidebar, topbar
    // and all) get inserted inside the target. We don't actually
    // implement the modifiers; they're parsed and discarded so authors
    // don't trip on a syntax that looks valid.
    if (mode) mode = String(mode).trim().split(/\s+/)[0];
    if (mode === "outerHTML") {
      var wrap = document.createElement("div");
      wrap.innerHTML = html;
      if (target.parentNode) {
        // Move every parsed node into a fragment so leading/trailing
        // whitespace text nodes don't cause the real element to be
        // dropped. (Bug seen when a Jinja partial starts with a
        // {# comment #} that leaves a stray "\n" ahead of the tag —
        // wrap.firstChild was the text node, the <section> stayed in
        // wrap, and the swap target effectively vanished.)
        var frag = document.createDocumentFragment();
        var newElements = [];
        while (wrap.firstChild) {
          var node = wrap.firstChild;
          if (node.nodeType === 1) newElements.push(node);
          frag.appendChild(node);
        }
        var parent = target.parentNode;
        parent.replaceChild(frag, target);
        for (var k = 0; k < newElements.length; k++) {
          bind(newElements[k]);
          runScripts(newElements[k]);
        }
        // Fire afterSwap on the parent (target was just removed) so
        // ancestor listeners catch it via bubbling. detail.elt
        // mirrors real htmx's payload shape closely enough for the
        // listeners in this codebase.
        fireHxEvent(parent, "afterSwap", { elt: parent, target: parent });
      } else {
        target.outerHTML = html;
      }
      return;
    }
    if (mode === "beforeend" || mode === "afterbegin" ||
        mode === "beforebegin" || mode === "afterend") {
      // insertAdjacentHTML requires the target have a parent for
      // beforebegin/afterend; fall back to innerHTML otherwise.
      if ((mode === "beforebegin" || mode === "afterend") && !target.parentNode) {
        target.innerHTML = html;
        bind(target);
        fireHxEvent(target, "afterSwap", { elt: target, target: target });
        return;
      }
      // Track siblings / children that existed before insertion so
      // we can bind *only* the newly-added subtree.
      var before = new Set();
      var scanRoot = (mode === "beforeend" || mode === "afterbegin")
        ? target
        : target.parentNode;
      for (var i = 0; i < scanRoot.childNodes.length; i++) {
        before.add(scanRoot.childNodes[i]);
      }
      target.insertAdjacentHTML(mode, html);
      for (var j = 0; j < scanRoot.childNodes.length; j++) {
        var node = scanRoot.childNodes[j];
        if (!before.has(node) && node.nodeType === 1) {
          bind(node);
          runScripts(node);
        }
      }
      fireHxEvent(target, "afterSwap", { elt: target, target: target });
      return;
    }
    target.innerHTML = html;
    bind(target);
    runScripts(target);
    fireHxEvent(target, "afterSwap", { elt: target, target: target });
  }

  function handleTrigger(header) {
    if (!header) return;
    header.split(",").forEach(function (name) {
      name = name.trim();
      if (!name) return;
      document.body.dispatchEvent(new CustomEvent(name, { bubbles: true }));
    });
  }

  function parseHxVals(el) {
    var raw = el.getAttribute("hx-vals");
    if (!raw) return null;
    try { return JSON.parse(raw); } catch (e) { return null; }
  }

  // Resolve hx-include to a list of elements whose form controls
  // should be merged into the outgoing request. Supports "closest
  // <sel>" and plain CSS selectors (comma-separated allowed).
  function includeEls(el) {
    var raw = el.getAttribute("hx-include");
    if (!raw) return [];
    var out = [];
    raw.split(",").forEach(function (seg) {
      seg = seg.trim();
      if (!seg) return;
      if (seg === "this") {
        // Special keyword from real-htmx: include the element itself.
        // Without this branch the shim treated "this" as a CSS selector,
        // querySelectorAll threw, the catch swallowed it, and the
        // include list ended up empty — meaning per-row Paperless
        // search hx-get's never carried ?q=... into the request.
        out.push(el);
      } else if (seg.indexOf("closest ") === 0) {
        var c = el.closest(seg.slice(8).trim());
        if (c) out.push(c);
      } else if (seg.indexOf("find ") === 0) {
        var f = qs(el, seg.slice(5).trim());
        if (f) out.push(f);
      } else {
        try {
          var list = document.querySelectorAll(seg);
          for (var i = 0; i < list.length; i++) out.push(list[i]);
        } catch (e) {}
      }
    });
    return out;
  }

  // Append every form control found inside `root` to `fd`, skipping
  // the button/control that triggered the request so the browser-
  // native submit-button semantics (only the clicked button's value
  // is submitted) aren't violated. Matches native FormData behavior
  // for checkboxes (unchecked → excluded) and multi-select.
  function appendControls(fd, root, triggerEl) {
    if (!root) return;
    var controls;
    if (root.tagName === "FORM") {
      // Use the browser's own serializer for a real form.
      var formFd = new FormData(root);
      formFd.forEach(function (v, k) { fd.append(k, v); });
      return;
    }
    // Self-include: hx-include="this" passes the trigger element itself
    // as `root`. If that element is an input/select/textarea, include
    // its own value (querySelectorAll wouldn't find it because it only
    // returns descendants). Real-htmx semantics: the element-itself
    // case carries name=value into the request.
    var rootTag = (root.tagName || "").toLowerCase();
    if (rootTag === "input" || rootTag === "select" || rootTag === "textarea") {
      if (root.name && !root.disabled) {
        var rt = (root.type || "").toLowerCase();
        if ((rt === "checkbox" || rt === "radio")) {
          if (root.checked) fd.append(root.name, root.value);
        } else if (rootTag === "select" && root.multiple) {
          for (var jj = 0; jj < root.options.length; jj++) {
            if (root.options[jj].selected) fd.append(root.name, root.options[jj].value);
          }
        } else {
          fd.append(root.name, root.value);
        }
      }
      return;
    }
    controls = root.querySelectorAll("input, select, textarea");
    for (var i = 0; i < controls.length; i++) {
      var c = controls[i];
      if (c === triggerEl) continue;
      if (!c.name) continue;
      if (c.disabled) continue;
      var t = (c.type || "").toLowerCase();
      if ((t === "checkbox" || t === "radio") && !c.checked) continue;
      if (c.tagName === "SELECT" && c.multiple) {
        for (var j = 0; j < c.options.length; j++) {
          if (c.options[j].selected) fd.append(c.name, c.options[j].value);
        }
        continue;
      }
      fd.append(c.name, c.value);
    }
  }

  // Resolve the method/url pair. Forms can have hx-post/hx-get OR fall
  // back to action+method; non-form elements MUST have one of the hx-*.
  function resolveRequest(el) {
    var url = el.getAttribute("hx-post");
    if (url) return { method: "POST", url: url };
    url = el.getAttribute("hx-get");
    if (url) return { method: "GET", url: url };
    url = el.getAttribute("hx-delete");
    if (url) return { method: "DELETE", url: url };
    if (el.tagName === "FORM") {
      return { method: (el.method || "POST").toUpperCase(), url: el.action };
    }
    return null;
  }

  function fire(el, ev) {
    if (ev) ev.preventDefault();

    var confirmMsg = el.getAttribute("hx-confirm");
    if (confirmMsg && !window.confirm(confirmMsg)) return;

    var req = resolveRequest(el);
    if (!req) return;
    var target = findTarget(el);
    var mode = el.getAttribute("hx-swap") || "innerHTML";

    var fetchOpts = {
      method: req.method,
      headers: { "HX-Request": "true" },
      credentials: "same-origin",
    };
    // CSRF: every state-changing request must carry the X-CSRF-Token
    // header so the auth middleware (ADR-0050) admits it. The token
    // lives in the lamella_csrf cookie (httponly=false specifically
    // so JS can read it). Done here in the shim because the upstream
    // htmx:configRequest event is not emitted by this shim, so a
    // base.html-level listener can't add it. Skipped on safe methods
    // (the middleware bypasses GET/HEAD/OPTIONS anyway).
    (function () {
      var m = (req.method || "").toUpperCase();
      if (m === "GET" || m === "HEAD" || m === "OPTIONS") return;
      var SECURE = "__Host-lamella_csrf";
      var INSECURE = "lamella_csrf";
      var prefer = location.protocol === "https:" ? SECURE : INSECURE;
      var parts = (document.cookie || "").split(";");
      var token = "";
      for (var i = 0; i < parts.length; i++) {
        var c = parts[i].trim();
        if (c.indexOf(prefer + "=") === 0) {
          token = decodeURIComponent(c.substring(prefer.length + 1));
          break;
        }
        if (!token && c.indexOf(INSECURE + "=") === 0) {
          token = decodeURIComponent(c.substring(INSECURE.length + 1));
        }
      }
      if (token) fetchOpts.headers["X-CSRF-Token"] = token;
    })();

    var includes = includeEls(el);

    if (req.method === "POST" || req.method === "PUT" || req.method === "PATCH" || req.method === "DELETE") {
      var bodyFd;
      if (el.tagName === "FORM") {
        bodyFd = new FormData(el);
      } else {
        bodyFd = new FormData();
        // If the trigger is itself a named input (e.g. checkbox),
        // include its value so form-ish buttons behave predictably.
        if (el.name && (el.tagName === "INPUT" || el.tagName === "SELECT" || el.tagName === "TEXTAREA")) {
          var tt = (el.type || "").toLowerCase();
          if (tt !== "checkbox" && tt !== "radio") bodyFd.append(el.name, el.value);
          else if (el.checked) bodyFd.append(el.name, el.value);
        }
      }
      for (var ii = 0; ii < includes.length; ii++) {
        appendControls(bodyFd, includes[ii], el);
      }
      var extra = parseHxVals(el);
      if (extra) {
        for (var k in extra) {
          if (Object.prototype.hasOwnProperty.call(extra, k)) bodyFd.append(k, extra[k]);
        }
      }
      // Only attach a body if we actually have anything to send,
      // so plain hx-post buttons with nothing to include stay
      // body-less (matches the old behavior).
      var hasAny = false;
      bodyFd.forEach(function () { hasAny = true; });
      if (hasAny) fetchOpts.body = bodyFd;
    } else if (req.method === "GET") {
      var usp = new URLSearchParams();
      for (var iii = 0; iii < includes.length; iii++) {
        var gfd = new FormData();
        appendControls(gfd, includes[iii], el);
        gfd.forEach(function (v, k) { usp.append(k, v); });
      }
      var extraG = parseHxVals(el);
      if (extraG) {
        for (var kk in extraG) {
          if (Object.prototype.hasOwnProperty.call(extraG, kk)) usp.set(kk, extraG[kk]);
        }
      }
      var qs2 = usp.toString();
      if (qs2) req.url += (req.url.indexOf("?") >= 0 ? "&" : "?") + qs2;
    }

    setBusy(el, true);

    // Run any inline `hx-on::after-request` (or the colon-form
    // `hx-on:htmx:after-request`) handler on the trigger element.
    // Mirrors the real-htmx semantics — the handler body executes
    // with `event`, `this`, and `window` in scope; `event.detail`
    // carries `successful` (2xx response) and `xhr`-shaped fields
    // so existing inline checks like
    //   "if (event.detail.successful) { ... }"
    // work without modification.
    function runAfterRequestHandlers(success, response) {
      var attrs = [
        "hx-on::after-request",
        "hx-on:htmx:after-request",
        // Some templates use the dash-only form; tolerate it.
        "hx-on--after-request",
      ];
      var body = null;
      for (var i = 0; i < attrs.length; i++) {
        body = el.getAttribute(attrs[i]);
        if (body) break;
      }
      if (!body) return;
      try {
        var fn = new Function(
          "event",
          "this.__lamellaHxOn = true; " + body
        );
        var event = {
          type: "htmx:afterRequest",
          target: el,
          detail: {
            successful: !!success,
            elt: el,
            xhr: response || null,
          },
        };
        fn.call(el, event);
      } catch (err) {
        if (window.console && console.warn) {
          console.warn("hx-on::after-request handler failed:", err, body);
        }
      }
    }

    fetch(req.url, fetchOpts).then(function (r) {
      handleTrigger(r.headers.get("HX-Trigger"));
      // HX-Redirect / HX-Location: full client-side nav.
      var redirect = r.headers.get("HX-Redirect") || r.headers.get("HX-Location");
      if (redirect) {
        runAfterRequestHandlers(r.ok, r);
        window.location.assign(redirect);
        return;
      }
      if (r.headers.get("HX-Refresh") === "true") {
        runAfterRequestHandlers(r.ok, r);
        window.location.reload();
        return;
      }
      return r.text().then(function (text) {
        if (r.ok) {
          // Pull out-of-band elements first — they're processed
          // independently of the primary swap target and get
          // stripped from the remaining HTML.
          var mainHtml = processOob(text);
          // hx-select: slice the response down to a single element
          // before swapping. Lets a route returning a full page
          // serve as the source for an in-page swap without the
          // entire shell getting inserted into the target. The
          // server-side partial-on-HX-Request pattern is preferred,
          // but hx-select is the safety net for routes that don't
          // have one yet.
          var selectSel = el.getAttribute("hx-select");
          if (selectSel) {
            try {
              var doc = new DOMParser().parseFromString(
                mainHtml, "text/html"
              );
              var picked = doc.querySelector(selectSel);
              mainHtml = picked ? picked.outerHTML : "";
            } catch (e) { /* keep mainHtml as-is on parse failure */ }
          }
          // hx-swap="none" suppresses the swap entirely — useful when
          // the response is a 204 / status-only and the caller plans
          // to do its own DOM work via hx-on::after-request. Without
          // this branch, mode === "none" fell through to innerHTML
          // and dumped an empty body into the target.
          if (mode !== "none") {
            swap(target, mainHtml, mode);
          }
          if (el.tagName === "FORM" && el.hasAttribute("hx-reset")) el.reset();
        } else {
          // Error responses (4xx/5xx) used to wrap the body text in a
          // <div class="error"> and dump it into the original swap
          // target (e.g. body+beforeend on Ask AI), which left the
          // error pinned to the bottom of the page where users
          // couldn't see it. Now: process OOB swaps the same way the
          // success branch does so server-side error toasts can land
          // in #toast-area regardless of the original target. Also
          // honor HX-Retarget / HX-Reswap response headers (subset of
          // real htmx.org behavior) so server handlers can route a
          // visible error message to a stable target. If the server
          // returned ONLY OOB content (mainErr empty after extraction),
          // skip the primary swap entirely so the bottom of the page
          // stays clean.
          var mainErr = processOob(text || "");
          var errTarget = target;
          var errMode = mode;
          var retargetSel = r.headers.get("HX-Retarget");
          if (retargetSel) {
            var rt = document.querySelector(retargetSel);
            if (rt) errTarget = rt;
          }
          var reswapMode = r.headers.get("HX-Reswap");
          if (reswapMode) errMode = reswapMode;
          if (mainErr.trim()) {
            swap(
              errTarget,
              '<div class="error">' + mainErr + "</div>",
              errMode
            );
          }
          // No fallthrough to the original target when the response
          // was 100% OOB — the OOB toast already informed the user.
        }
        runAfterRequestHandlers(r.ok, r);
      });
    }).catch(function (err) {
      swap(target, '<div class="error">' + (err && err.message || err) + "</div>", mode);
      runAfterRequestHandlers(false, null);
    }).then(function () {
      setBusy(el, false);
    });
  }

  // Strip and apply any top-level elements with hx-swap-oob. Returns
  // the remaining HTML (without the OOB nodes) so the primary swap
  // target only gets the non-OOB content. Each OOB element targets
  // an element in the document by id (its own id attribute); the
  // `hx-swap-oob` value picks the swap mode: "true" (default,
  // outerHTML replace), "innerHTML", "beforeend", etc.
  function processOob(html) {
    if (!html || html.indexOf("hx-swap-oob") === -1) return html;
    var wrap = document.createElement("div");
    wrap.innerHTML = html;
    var oobNodes = [];
    for (var i = 0; i < wrap.children.length; i++) {
      var child = wrap.children[i];
      if (child.hasAttribute && child.hasAttribute("hx-swap-oob")) {
        oobNodes.push(child);
      }
    }
    oobNodes.forEach(function (node) {
      var mode = node.getAttribute("hx-swap-oob") || "true";
      node.removeAttribute("hx-swap-oob");
      // Selector-form mode: "<mode>:<css-selector>" lets the response
      // target an element by attribute / class / data- selector
      // instead of requiring the matching id on both ends. Mirrors
      // the upstream htmx.org behavior so existing templates can
      // route OOB tiles to elements identified by data-rsg-staged-ids
      // or similar without needing to compute the original element id.
      var selectorMode = null;
      var colonIdx = mode.indexOf(":");
      if (colonIdx > 0) {
        selectorMode = mode.slice(colonIdx + 1).trim();
        mode = mode.slice(0, colonIdx).trim();
      }
      var targetEl = null;
      if (selectorMode) {
        try { targetEl = document.querySelector(selectorMode); }
        catch (e) { targetEl = null; }
      } else {
        var id = node.getAttribute("id");
        if (id) targetEl = document.getElementById(id);
      }
      if (!targetEl) {
        // Without an id or a resolvable selector, drop the OOB node.
        node.parentNode && node.parentNode.removeChild(node);
        return;
      }
      if (mode === "true" || mode === "outerHTML") {
        targetEl.parentNode.replaceChild(node, targetEl);
        if (node.nodeType === 1) { bind(node); runScripts(node); }
      } else if (mode === "innerHTML") {
        targetEl.innerHTML = node.innerHTML;
        bind(targetEl);
        runScripts(targetEl);
      } else if (mode === "beforeend" || mode === "afterbegin" ||
                 mode === "beforebegin" || mode === "afterend") {
        var before = new Set();
        var scanRoot = (mode === "beforeend" || mode === "afterbegin")
          ? targetEl
          : targetEl.parentNode;
        for (var j = 0; j < scanRoot.childNodes.length; j++) {
          before.add(scanRoot.childNodes[j]);
        }
        targetEl.insertAdjacentHTML(mode, node.outerHTML);
        for (var k = 0; k < scanRoot.childNodes.length; k++) {
          var added = scanRoot.childNodes[k];
          if (!before.has(added) && added.nodeType === 1) {
            bind(added);
            runScripts(added);
          }
        }
        node.parentNode && node.parentNode.removeChild(node);
      } else {
        // Unknown mode — fall back to outerHTML replace.
        targetEl.parentNode.replaceChild(node, targetEl);
        if (node.nodeType === 1) { bind(node); runScripts(node); }
      }
    });
    return wrap.innerHTML;
  }

  // ---------- binding ----------

  function parseTriggers(el) {
    var raw = el.getAttribute("hx-trigger");
    if (!raw) {
      // Default: submit for forms, click for everything else.
      return el.tagName === "FORM" ? [{ name: "submit" }] : [{ name: "click" }];
    }
    // Multiple triggers comma-separated; each may include modifiers.
    return raw.split(",").map(function (s) {
      s = s.trim();
      var parts = s.split(/\s+/);
      var name = parts.shift();
      // "every Ns" / "every Nms" — polling trigger. The interval
      // value is the next whitespace-separated token.
      if (name === "every" && parts.length) {
        var raw2 = parts.shift();
        var ms = 0;
        if (/ms$/.test(raw2)) ms = parseInt(raw2, 10);
        else if (/s$/.test(raw2)) ms = parseInt(raw2, 10) * 1000;
        else ms = parseInt(raw2, 10) || 0;
        return { name: "every", intervalMs: ms };
      }
      var once = false, changed = false, delay = 0;
      for (var i = 0; i < parts.length; i++) {
        var p = parts[i];
        if (p === "once") once = true;
        else if (p === "changed") changed = true;
        else if (p.indexOf("delay:") === 0) {
          var d = p.slice(6);
          if (/ms$/.test(d)) delay = parseInt(d, 10);
          else if (/s$/.test(d)) delay = parseInt(d, 10) * 1000;
          else delay = parseInt(d, 10) || 0;
        }
      }
      return { name: name, once: once, changed: changed, delay: delay };
    });
  }

  function bindOne(el) {
    if (el.__hxBound) return;
    el.__hxBound = true;

    var triggers = parseTriggers(el);
    var lastValue = el.value;

    triggers.forEach(function (t) {
      if (t.name === "load") {
        // Fire once, asynchronously, after binding so the DOM is settled.
        setTimeout(function () { fire(el, null); }, 0);
        return;
      }
      if (t.name === "every") {
        // Polling trigger. setInterval fires fire(el) every N ms until
        // (a) the element leaves the document, or (b) hx-trigger is
        // removed from the element (callers stop a polling loop by
        // doing el.removeAttribute("hx-trigger") — see the
        // _job_modal.html polling-stop logic that flips off once a
        // job hits a terminal status).
        if (!t.intervalMs || t.intervalMs < 50) return;
        var handle = setInterval(function () {
          if (!document.body.contains(el)) {
            clearInterval(handle);
            return;
          }
          if (!el.getAttribute("hx-trigger")) {
            clearInterval(handle);
            return;
          }
          fire(el, null);
        }, t.intervalMs);
        return;
      }
      if (t.name === "toggle") {
        // Native <details> toggle event; "once" is almost always what we want.
        var handler = function (ev) {
          // Only fire when opening, not closing.
          if (el.tagName === "DETAILS" && !el.open) return;
          fire(el, null);
          if (t.once) el.removeEventListener("toggle", handler);
        };
        el.addEventListener("toggle", handler);
        return;
      }
      if (t.name === "submit") {
        el.addEventListener("submit", function (ev) { fire(el, ev); });
        return;
      }
      if (t.name === "click") {
        el.addEventListener("click", function (ev) { fire(el, ev); });
        return;
      }
      // Generic DOM event (change, input, custom).
      var timer = null;
      el.addEventListener(t.name, function (ev) {
        if (t.changed) {
          if (el.value === lastValue) return;
          lastValue = el.value;
        }
        if (t.delay) {
          if (timer) clearTimeout(timer);
          timer = setTimeout(function () { fire(el, null); }, t.delay);
        } else {
          fire(el, ev);
        }
        if (t.once) el.__hxBound = true; // prevents rebind; leave listener attached
      });
    });
  }

  function bind(root) {
    if (!root || !root.querySelectorAll) return;
    // Anything with hx-post, hx-get, or hx-delete needs binding.
    var all = root.querySelectorAll("[hx-post], [hx-get], [hx-delete]");
    for (var i = 0; i < all.length; i++) bindOne(all[i]);
    // Also catch root itself if it has hx-*.
    if (root.nodeType === 1 && (
      root.hasAttribute("hx-post") ||
      root.hasAttribute("hx-get") ||
      root.hasAttribute("hx-delete")
    )) bindOne(root);
  }

  // Re-execute any <script> tags in newly-inserted content. The
  // browser parses scripts inserted via innerHTML / insertAdjacentHTML
  // as inert nodes — they don't run on their own. Real htmx.org
  // explicitly evaluates them; this mirrors that behavior so partials
  // that include <script> blocks (e.g. _job_modal.html's polling-stop
  // listener) actually wire up after a swap. Called only from swap()
  // and processOob() — NOT from the initial page-load bind(document)
  // because the browser already executed those.
  function runScripts(root) {
    if (!root || !root.querySelectorAll) return;
    var scripts;
    if (root.nodeType === 1 && root.tagName === "SCRIPT") {
      scripts = [root];
    } else {
      scripts = root.querySelectorAll("script");
    }
    for (var i = 0; i < scripts.length; i++) {
      var oldEl = scripts[i];
      // Skip type="application/json" / type="text/template" etc. —
      // only run real JS.
      var t = (oldEl.getAttribute("type") || "").toLowerCase();
      if (t && t !== "text/javascript" && t !== "application/javascript" &&
          t !== "module") continue;
      var newEl = document.createElement("script");
      for (var j = 0; j < oldEl.attributes.length; j++) {
        var a = oldEl.attributes[j];
        newEl.setAttribute(a.name, a.value);
      }
      newEl.text = oldEl.textContent;
      if (oldEl.parentNode) oldEl.parentNode.replaceChild(newEl, oldEl);
    }
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", function () { bind(document); });
  } else {
    bind(document);
  }

  // Programmatic ajax — used by page-level listeners that want to
  // refetch + swap a region without a user gesture. Mirrors the
  // upstream htmx.org `htmx.ajax(method, url, opts)` API surface so
  // existing templates don't have to special-case the shim.
  //
  // Wire shape: build a detached element carrying the hx-* attributes
  // that match the call args, then route it through `fire()` so the
  // CSRF-injection / swap-mode / target-resolution logic stays in one
  // place. The element is a one-shot — never bound, never reused —
  // so this can't accidentally double-fire.
  function ajax(method, url, opts) {
    opts = opts || {};
    var el = document.createElement("span");
    var m = (method || "GET").toUpperCase();
    if (m === "POST") el.setAttribute("hx-post", url);
    else if (m === "DELETE") el.setAttribute("hx-delete", url);
    else el.setAttribute("hx-get", url);
    // Target: pass either a CSS selector string or a node. When a
    // node, we synthesize a unique selector by stamping a temporary
    // id; cleaned up post-fire.
    var stamped = null;
    var t = opts.target;
    if (t) {
      if (typeof t === "string") {
        el.setAttribute("hx-target", t);
      } else if (t && t.nodeType === 1) {
        if (!t.id) {
          stamped = "lamella-ajax-target-" + Math.random().toString(36).slice(2, 10);
          t.id = stamped;
        }
        el.setAttribute("hx-target", "#" + (t.id || stamped));
      }
    }
    if (opts.swap) el.setAttribute("hx-swap", opts.swap);
    if (opts.values) {
      try { el.setAttribute("hx-vals", JSON.stringify(opts.values)); } catch (e) {}
    }
    // Detached element — fire() expects a valid DOM node but doesn't
    // require connection. The CSRF + headers + handlers all read
    // attributes, not parent context.
    document.body.appendChild(el);
    try { fire(el, null); }
    finally {
      // Cleanup: remove the synthetic node + the stamped id (if any).
      try { el.remove(); } catch (e) {}
      if (stamped && t && t.id === stamped) t.removeAttribute("id");
    }
  }

  // Expose minimal API so external code can re-scan if it injects nodes.
  window.htmx = window.htmx || { process: bind, ajax: ajax };
  if (window.htmx && !window.htmx.ajax) window.htmx.ajax = ajax;
})();
